function PBar({ pct, color, height = 6 }) {
  return (
    <div style={{ background: "#DDD5C4", borderRadius: 4, height, overflow: "hidden" }}>
      <div style={{ width: `${Math.min(pct,100)}%`, height: "100%", background: color, borderRadius: 4 }} />
    </div>
  );
}

// ── 藥包索引元件（必看／常看／選看）────────────────────────
function DrugPackage({ items }) {
  const [expanded, setExpanded] = useState(null);
  const levels = [
    { key:"must",   label:"必看", color:"#DC2626", bg:"#FEE2E2", icon:"🔴" },
    { key:"should", label:"常看", color:"#D97706", bg:"#FEF3C7", icon:"🟡" },
    { key:"could",  label:"選看", color:"#059669", bg:"#D1FAE5", icon:"🟢" },
  ];
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
      {items.map((item,i) => {
        const urgent  = item.daysLeft <= 30;
        const overdue = item.daysLeft < 0;
        const today   = item.daysLeft === 0;
        const hBg     = overdue||today ? "#FEE2E2" : urgent ? "#FEF3C7" : "#F0FDF4";
        const hBorder = overdue||today ? "#FCA5A5" : urgent ? "#FCD34D" : "#86EFAC";
        const hText   = overdue||today ? "#991B1B" : urgent ? "#92400E" : "#166534";
        const isOpen  = expanded === i;
        return (
          <div key={i} style={{ border:`1px solid ${hBorder}`, borderRadius:8, overflow:"hidden" }}>
            <div onClick={() => setExpanded(isOpen ? null : i)}
              style={{ background:hBg, padding:"6px 8px", cursor:"pointer", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <div>
                <div style={{ fontSize:10, fontWeight:800, color:hText }}>💊 {item.label}</div>
                <div style={{ fontSize:9, color:"#9E836A", marginTop:1 }}>{item.date}</div>
              </div>
              <div style={{ display:"flex", alignItems:"center", gap:6 }}>
                <span style={{ fontSize:12, fontWeight:900, color:hText }}>
                  {overdue ? `🚨逾${Math.abs(item.daysLeft)}天` : today ? "🚨今日" : `D-${item.daysLeft}`}
                </span>
                <span style={{ fontSize:9, color:hText }}>{isOpen ? "▲" : "▼"}</span>
              </div>
            </div>
            {isOpen && (
              <div style={{ background:"#FAFAF7", padding:"8px 10px", borderTop:`1px solid ${hBorder}` }}>
                <div style={{ fontSize:10, fontWeight:800, color:"#7C3AED", marginBottom:6 }}>
                  📚 KM／EL 先備知識分級閱讀
                </div>
                {levels.map(lv => (
                  item[lv.key] && item[lv.key].length > 0 && (
                    <div key={lv.key} style={{ marginBottom:7 }}>
                      <div style={{
                        display:"inline-flex", alignItems:"center", gap:4,
                        background:lv.bg, border:`1px solid ${lv.color}40`,
                        borderRadius:4, padding:"2px 8px", marginBottom:4,
                      }}>
                        <span style={{ fontSize:9 }}>{lv.icon}</span>
                        <span style={{ fontSize:10, fontWeight:800, color:lv.color }}>{lv.label}</span>
                      </div>
                      {item[lv.key].map((km,j) => (
                        <div key={j} style={{ display:"flex", gap:5, marginBottom:3, paddingLeft:4 }}>
                          <span style={{ color:lv.color, fontSize:9, flexShrink:0, marginTop:1 }}>▸</span>
                          <span style={{ fontSize:10, color:"#3D2E1E", lineHeight:1.5 }}>{km}</span>
                        </div>
                      ))}
                    </div>
                  )
                ))}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

// ── 格內容 ────────────────────────────────────────────────
function CellContent({ proj, colId }) {
  const d = proj.data[colId];
  const c = proj.color;

  if (colId === "drug") return <DrugPackage items={d} color={c} />;

  if (colId === "diff") {
    const cfg = {
      up:   { icon:"▲", bg:"#D1FAE5", border:"#6EE7B7", text:"#065F46" },
      down: { icon:"▼", bg:"#FEE2E2", border:"#FCA5A5", text:"#991B1B" },
      warn: { icon:"⚠", bg:"#FEF3C7", border:"#FCD34D", text:"#92400E" },
      same: { icon:"─", bg:"#F1F5F9", border:"#CBD5E1", text:"#475569" },
    };
    return (
      <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
        {d.map((item,i) => {
          const s = cfg[item.type] || cfg.same;
          return (
            <div key={i} style={{ display:"flex", gap:6, alignItems:"flex-start", background:s.bg, border:`1px solid ${s.border}`, borderRadius:5, padding:"4px 7px" }}>
              <span style={{ fontSize:10, color:s.text, fontWeight:800, flexShrink:0, marginTop:1 }}>{s.icon}</span>
              <span style={{ fontSize:10, color:s.text, lineHeight:1.5 }}>{item.text}</span>
            </div>
          );
        })}
      </div>
    );
  }

  if (colId === "overview") return (
    <div>
      <p style={{ fontSize:11, color:"#5C4A35", lineHeight:1.6, marginBottom:8 }}>{d.summary}</p>
      {d.kpis.map(([k,v],i) => (
        <div key={i} style={{ display:"flex", justifyContent:"space-between", fontSize:11, padding:"3px 0", borderBottom:"1px solid #DDD5C4" }}>
          <span style={{ color:"#9E836A" }}>{k}</span>
          <span style={{ fontWeight:700, color:c }}>{v}</span>
        </div>
      ))}
    </div>
  );

  if (colId === "milestone") return (
    <div style={{ display:"flex", flexDirection:"column", gap:4 }}>
      {d.map((m,i) => (
        <div key={i} style={{ display:"flex", gap:6, alignItems:"flex-start" }}>
          <span style={{ fontSize:9, fontWeight:800, color:c, minWidth:36, paddingTop:1, flexShrink:0 }}>{m.date}</span>
          <span style={{ fontSize:10, color:"#4A3828", lineHeight:1.5 }}>{m.label}</span>
        </div>
      ))}
    </div>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:3 }}>
      {d.map((item,i) => (
        <div key={i} style={{ display:"flex", gap:5, alignItems:"flex-start" }}>
          <span style={{ color:c, fontSize:9, marginTop:2, flexShrink:0 }}>▸</span>
          <span style={{ fontSize:10, color:"#4A3828", lineHeight:1.5 }}>{item}</span>
        </div>
      ))}
    </div>
  );
}

// ── AI 解析 PPTX ──────────────────────────────────────────
async function readFileAsBase64(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result.split(',')[1]);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

async function parseReportWithAI(file, currentProjects) {
  const base64 = await readFileAsBase64(file);
  const prompt = `你是工程週報解析助理。以下是一份潤弘/潤泰建築工程整合週報的PPTX（base64）。

請解析後回傳**純JSON**，格式完全如下（不要加任何說明文字或markdown）：
{
  "reportDate": "日期範圍如 6/8～6/14",
  "projects": [
    {
      "id": "專案id（global/tainan/xindu/huancui/huwee/nangang其中之一）",
      "progress": 整體進度百分比數字,
      "highlight": "本週最重要一句話",
      "overview_summary": "總覽摘要一段話",
      "overview_kpis": [["指標名","值"],["指標名","值"],["指標名","值"]],
      "milestone": [{"date":"日期","label":"說明"}],
      "weekly": ["重點1","重點2","重點3","重點4","重點5"],
      "safety": ["安衞1","安衞2","安衞3"],
      "quality": ["品質1","品質2","品質3"],
      "mep": ["機電1","機電2","機電3"],
      "km": ["KM1","KM2","KM3"],
      "diff": [{"type":"up/down/warn/same","text":"與上週差異說明"}]
    }
  ]
}

專案id對應：全球人壽→global、台南群聯→tainan、新都段→xindu、環翠段→huancui、臺大虎尾→huwee、南港之星→nangang

只回傳JSON，不要其他文字。`;

  const response = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 4000,
      messages: [{
        role: "user",
        content: [
          { type: "document", source: { type: "base64", media_type: "application/pdf", data: base64 } },
          { type: "text", text: prompt }
        ]
      }]
    })
  });

  const data = await response.json();
  const text = data.content?.filter(b => b.type === "text").map(b => b.text).join("") || "";
  const clean = text.replace(/```json|```/g, "").trim();
  return JSON.parse(clean);
}

